import{Ct as e,ct as t,lt as n,q as r}from"./chunks/framework.BVmwMUcr.js";var i=JSON.parse(`{"title":"Chinese Mathematics Competition (CMC)","description":"Introduction to the Chinese Mathematics Competition (CMC) and a simple participation guide","frontmatter":{"lang":"en-US","title":"Chinese Mathematics Competition (CMC)","description":"Introduction to the Chinese Mathematics Competition (CMC) and a simple participation guide","llm_translated":true},"headers":[],"relativePath":"en/learn/extra/contest/cmc.md","filePath":"en/learn/extra/contest/cmc.md","lastUpdated":1784829332000}`),a={name:`en/learn/extra/contest/cmc.md`};function o(r,i,a,o,s,c){return e(),t(`div`,null,[...i[0]||=[n(`<div style="display:none;" hidden="true" aria-hidden="true" data-nosnippet>Are you an LLM? You can read better optimized documentation at /en/learn/extra/contest/cmc.md for this page in Markdown format</div><h1 id="chinese-mathematics-competition-cmc" tabindex="-1">Chinese Mathematics Competition (CMC) <a class="header-anchor" href="#chinese-mathematics-competition-cmc" aria-label="Permalink to “Chinese Mathematics Competition (CMC)”">​</a></h1><p><strong>Organizer: Chinese Mathematical Society</strong></p><h3 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to “Overview”">​</a></h3><p>The Chinese Mathematics Competition for College Students (abbreviated as CMC) is a national high-level academic competition organized by the Chinese Mathematical Society for undergraduate students. It is divided into three groups: <strong>Mathematics Group</strong>, <strong>Non-Mathematics Group A</strong>, and <strong>Non-Mathematics Group B</strong>.</p><p><strong>The preliminary round is at the provincial level. The top 15 candidates in each province can advance to the national finals.</strong></p><h3 id="exam-content" tabindex="-1">Exam Content <a class="header-anchor" href="#exam-content" aria-label="Permalink to “Exam Content”">​</a></h3><ul><li><strong>Mathematics Group</strong>: Calculus, Linear Algebra, Analytic Geometry</li><li><strong>Non-Mathematics Group A</strong>: Calculus</li><li><strong>Non-Mathematics Group B</strong>: Calculus (simplified)</li></ul><h3 id="benefits" tabindex="-1">Benefits <a class="header-anchor" href="#benefits" aria-label="Permalink to “Benefits”">​</a></h3><ul><li><strong>Comprehensive evaluation (intellectual development) bonus points</strong>: Provincial first prize: 5 points, second prize: 3 points, third prize: 1 point (<strong>PS: Intellectual development points are tripled</strong>)</li><li><strong>Graduate recommendation bonus</strong>: National first prize can help with postgraduate recommendation</li></ul><hr><h3 id="registration-period" tabindex="-1">Registration Period <a class="header-anchor" href="#registration-period" aria-label="Permalink to “Registration Period”">​</a></h3><p>Mid-September to end of September. Follow announcements from the <a href="https://www2.scut.edu.cn/math/" target="_blank" rel="noreferrer">SCUT School of Mathematics</a>.</p><h4 id="option-1-outstanding-in-school-competition" tabindex="-1">Option 1: Outstanding in School Competition <a class="header-anchor" href="#option-1-outstanding-in-school-competition" aria-label="Permalink to “Option 1: Outstanding in School Competition”">​</a></h4><p>Participate in the SCUT Mathematics Competition held at the start of the fall semester. First prize winners can have their registration fee reimbursed.</p><h4 id="option-2-self-registration" tabindex="-1">Option 2: Self-Registration <a class="header-anchor" href="#option-2-self-registration" aria-label="Permalink to “Option 2: Self-Registration”">​</a></h4><p>Registration fee: 100 RMB</p><h3 id="competition-date" tabindex="-1">Competition Date <a class="header-anchor" href="#competition-date" aria-label="Permalink to “Competition Date”">​</a></h3><p>Early November each year</p><hr><h3 id="preparation-strategy-mathematics-group" tabindex="-1">Preparation Strategy (Mathematics Group) <a class="header-anchor" href="#preparation-strategy-mathematics-group" aria-label="Permalink to “Preparation Strategy (Mathematics Group)”">​</a></h3><p>Coming soon</p><hr><h3 id="preparation-strategy-non-mathematics-group" tabindex="-1">Preparation Strategy (Non-Mathematics Group) <a class="header-anchor" href="#preparation-strategy-non-mathematics-group" aria-label="Permalink to “Preparation Strategy (Non-Mathematics Group)”">​</a></h3><h4 id="crash-course-suitable-for-freshmen-looking-to-win-awards-quickly" tabindex="-1">Crash Course (Suitable for freshmen looking to win awards quickly) <a class="header-anchor" href="#crash-course-suitable-for-freshmen-looking-to-win-awards-quickly" aria-label="Permalink to “Crash Course (Suitable for freshmen looking to win awards quickly)”">​</a></h4><p><strong>Disclosure</strong>: 2024 cohort, Oplisty, Guangdong Provincial First Prize</p><p>Since most of the exam focuses on Calculus, you must <strong>thoroughly study Calculus I</strong>. I recommend taking one month — that is, <strong>speed through Calculus I in the first month of the semester</strong>. I used the textbook <strong>Advanced Calculus (Tsinghua University Press)</strong>. For each chapter, <strong>read the text and do the end-of-chapter problems, skip the chapter review exercises</strong>. This takes one month. Then in <strong>October, speed through Calculus II</strong>, using the same <strong>Advanced Calculus</strong> textbook. A week before the exam, log into the <a href="https://www.cmathc.org.cn/shiti/" target="_blank" rel="noreferrer">CMC official website</a> to practice past papers. <strong>Memorize the solutions for problems you can&#39;t solve.</strong></p><p>What, you&#39;ve been slacking off?</p><p>No worries!</p><p>At its core, this is an exam, and its difficulty level is roughly comparable to finals at mid-to-top-tier 985 universities. Since they can speed through it, why can&#39;t you?</p><p><strong>Go to Bilibili, search for crash-course videos, watch them, and then start solving problems immediately.</strong> Focus areas:</p><ul><li>Line, surface, double, and triple integrals</li><li>Series (guaranteed to be the last problem, may also appear as fill-in-the-blank)</li><li>Partial derivative calculations and the chain rule</li><li>Common limit-solving techniques</li><li>Differential equations</li></ul><p><strong>Prioritize the topics above</strong> — at minimum you&#39;ll get provincial third prize. With a bit more effort, second or first prize is achievable.</p><h4 id="study-materials" tabindex="-1">Study Materials <a class="header-anchor" href="#study-materials" aria-label="Permalink to “Study Materials”">​</a></h4><p>One book is enough — you probably won&#39;t have time for more anyway.</p><ul><li>CMC Analytical Tutorial Volumes 1 &amp; 2 (Red book series: Science Press)</li></ul>`,36)]])}var s=r(a,[[`render`,o]]);export{i as __pageData,s as default};